import{_ as e,o as a,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"霜月","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/霜月.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/霜月.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/霜月.md"};function o(d,b,l,i,_,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"霜月",tabindex:"-1"},[n("霜月 "),r("a",{class:"header-anchor",href:"#霜月","aria-label":'Permalink to "霜月"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),s('<h1 id="霜月-1" tabindex="-1">霜月 <a class="header-anchor" href="#霜月-1" aria-label="Permalink to &quot;霜月&quot;">​</a></h1><p>该武器差价升级<br> 霜月-林<br> 神话本质<br> D+500<br> 一把传说中用居住在月宫的仙女提供的月之霜打造的武器。这把刀刀身像琉璃做成，全身幽蓝通透，刀脊挺直，线条流畅而冷冽，月光照射时，刀身便会流转着淡淡的银辉。<br> 据说被上上任主人拿来当菜刀用。<br> 特殊的，所有需要先将刀归鞘来使用的技艺无法用霜月来释放。<br> 武器类别：武士刀<br> 专业：刀（且无法使用任何其他专业替代）<br> 武器伤害：6L<br> 体积：3<br> 特性：高速1，【凛月】，【却邪】<br> 凛月：获得时选择你的一个已有能量池，不能更改，将内气缠绕于霜月上会感到十分的轻灵感，且刀刃附近会散发出一些寒气，每次使用可以消耗东方的关键属性含有生理属性的能量施展攻击技时，减少2点能量消耗（最低为1），这个效果每轮生效一次。<br> 同时霜月还将逐渐承认主人的能力，为其敞开自己的力量，每场影片过后，霜月将额外为你储存3点能量，这视为扩大你能量池3点上限，该效果最多成长两次。<br> 却邪：月光引路，魑魅魍魉无可近身，你使用该武器具有【法破】。<br> =====</p><p>霜月-月煞-林<br> 神话本质<br> C+1000<br> 武器类别：武士刀<br> 专业：刀（且无法使用任何其他专业替代）<br> 武器伤害：11L<br> 体积：3<br> 特性：高速1，【凛月】，【却邪】，【月煞】<br> 凛月：获得时选择你的一个已有能量池，不能更改，将内气缠绕于霜月上会感到十分的轻灵感，且刀刃附近会散发出一些寒气，每次使用可以消耗东方的关键属性含有生理属性的能量施展攻击技时，减少2点能量消耗（最低为1），这个效果每轮生效一次。<br> 同时霜月还将逐渐承认主人的能力，为其敞开自己的力量，每场影片过后，霜月将额外为你储存3点能量，这视为扩大你能量池3点上限，该效果最多成长两次，升级不会重复生效。<br> 却邪：月光引路，魑魅魍魉无可近身，你使用该武器具有【法破】。<br> 月煞：霜月展现出自己的月之煞气，斩击已经无法被正常的手段所防御，是接近精神攻击的能力。<br> 你使用该武器进行攻击时不通过防御，而是以意志豁免对抗。<br> =====</p><p>霜月为C级时，你可以额外支付5xp让主神对霜月进行特殊强化，获得【转天地】<br> 转天地：月煞之气将你的武艺也转为刺杀心灵的能力，你的豪烈刀客专长的2级效果在你使用该武器攻击时，必须变为命中后目标对本次攻击出目进行意志豁免，失败则额外给予目标在意志豁免上的你力量属性一半的表现减值，持续一轮，不能用该来源的能力进行叠加，每次只能选择一个目标生效。<br> =====</p><p>霜月-月煞-奔月仙-林<br> 神话本质<br> B+2000<br> 武器类别：武士刀<br> 专业：刀（且无法使用任何其他专业替代）<br> 武器伤害：18L<br> 体积：3<br> 特性：高速1，【凛月】，【却邪】，【月煞】，【8加骰】，【广寒宫】<br> 凛月：获得时选择你的一个已有能量池，不能更改，将内气缠绕于霜月上会感到十分的轻灵感，且刀刃附近会散发出一些寒气，每次使用可以消耗东方的关键属性含有生理属性的能量施展攻击技时，减少2点能量消耗（最低为1），这个效果每轮生效一次。<br> 同时霜月还将逐渐承认主人的能力，为其敞开自己的力量，每场影片过后，霜月将额外为你储存3点能量，这视为扩大你能量池3点上限，该效果最多成长两次，升级不会重复生效。<br> 却邪：月光引路，魑魅魍魉无可近身，你使用该武器具有【法破】。<br> 月煞：霜月展现出自己的月之煞气，斩击已经无法被正常的手段所防御，是接近精神攻击的能力，<br> 你使用该武器进行攻击时不通过防御，而是以意志豁免对抗。<br> 广寒宫：霜月展露出它的本质，将敌人处于极寒的月宫之中。<br> 使用霜月可以同时攻击触及范围内的敌人，此时触及范围视作D困难地形，且你免疫C级环境来源的效果。<br> =====</p><p>霜月-月煞-奔月仙-斩金乌-林<br> 神话本质<br> A+4000<br> 武器类别：武士刀<br> 专业：刀（且无法使用任何其他专业替代）<br> 武器伤害：27L+6<br> 体积：3<br> 特性：高速1，【凛月】，【却邪】，【月煞】，【8加骰】，【广寒宫】，【斩金乌】<br> 凛月：获得时选择你的一个已有能量池，不能更改，将内气缠绕于霜月上会感到十分的轻灵感，且刀刃附近会散发出一些寒气，每次使用可以消耗东方的关键属性含有生理属性的能量施展攻击技时，减少2点能量消耗（最低为1），这个效果每轮生效一次。<br> 同时霜月还将逐渐承认主人的能力，为其敞开自己的力量，每场影片过后，霜月将额外为你储存3点能量，这视为扩大你能量池3点上限，该效果最多成长两次，升级不会重复生效。<br> 却邪：月光引路，魑魅魍魉无可近身，你使用该武器具有【法破】。<br> 月煞：霜月展现出自己的月之煞气，斩击已经无法被正常的手段所防御，是接近精神攻击的能力，<br> 你使用该武器进行攻击时不通过防御，而是以意志豁免对抗。<br> 广寒宫：霜月展露出它的本质，将敌人处于极寒的月宫之中。<br> 使用霜月可以同时攻击触及范围内的敌人，此时触及范围视作D困难地形。你同时免疫C级环境来源的效果。<br> 斩金乌：寒霜现在永远凝结在刀上，是遥远的炽热的旱灾之源被斩下的证明。<br> 使用霜月时，你的触及范围现在等同于你的敏感范围，触及范围内额外视为B级环境来源的太空环境，你现在免疫A级环境来源的效果。<br> =====</p><p>霜月-月煞-奔月仙-斩金乌-谁给这把刀加了这么多后缀啊-林-林<br> 神话本质<br> S+8000<br> 武器类别：武士刀<br> 专业：刀（且无法使用任何其他专业替代）<br> 武器伤害：38L+12<br> 体积：3<br> 特性：高速1，【凛月】，【却邪】，【月煞】，【8加骰】，【广寒宫】，【斩金乌】，【屠神无悔】，【寂灭九日】<br> 凛月：获得时选择你的一个已有能量池，不能更改，将内气缠绕于霜月上会感到十分的轻灵感，且刀刃附近会散发出一些寒气，每次使用可以消耗东方的关键属性含有生理属性的能量施展攻击技时，减少2点能量消耗（最低为1），这个效果每轮生效一次。<br> 同时霜月还将逐渐承认主人的能力，为其敞开自己的力量，每场影片过后，霜月将额外为你储存3点能量，这视为扩大你能量池3点上限，该效果最多成长两次，升级不会重复生效。<br> 却邪：月光引路，魑魅魍魉无可近身，你使用该武器具有【法破】。<br> 月煞：霜月展现出自己的月之煞气，斩击已经无法被正常的手段所防御，是接近精神攻击的能力，<br> 你使用该武器进行攻击时不通过防御，而是以意志豁免对抗。<br> 广寒宫：霜月展露出它的本质，将敌人处于极寒的月宫之中。<br> 使用霜月可以同时攻击触及范围内的敌人，此时触及范围视作D困难地形，你免疫C级环境来源的效果。<br> 斩金乌：寒霜现在永远凝结在刀上，是遥远的炽热的旱灾之源被斩下的证明。<br> 使用霜月时，你的触及范围现在等同于你的敏感范围，触及范围内额外视为B级环境来源的太空环境，你现在免疫A级环境来源的效果。<br> 屠神无悔：即使是生命之源的太阳神鸟，也毫不犹豫的斩下，神血浸满玉月，为月之霜。<br> 你使用霜月时将彻底爆发出泯灭金乌的力量，无尽的寒冷将缠绕在这把刀身上，只有展现出自己的屠神之志才能使用，将你的决心属性加入攻击检定，且使用霜月的攻击检定具有【传奇】特性。<br> 寂灭九日：而后即是永恒的寂静。<br> 霜月的神话本质彻底展现，九枚破碎太阳的虚影将显现在你的身后，对敌人爆发出惊人的力量，霜月攻击命中后，目标进行一次意志豁免对抗本次攻击出目，失败则将被九日虚影产生的引力进入超重状态，这是一个S级时空来源的改变重力效果。<br> =====</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=e(p,[["render",o]]);export{f as __pageData,m as default};
